// Extrai lead_id do webhook do Kommo
const raw = $input.item.json;
let leadId = null;

function hunter(obj) {
    if (!obj || typeof obj !== 'object') return;
    for (let key in obj) {
        const value = obj[key];
        const keyStr = decodeURIComponent(key);
        if ((keyStr.includes('[id]') || keyStr === 'id' || keyStr === 'lead_id') && !leadId && /^\d+$/.test(String(value))) {
            leadId = String(value);
        }
        if (typeof value === 'object') hunter(value);
    }
}
hunter(raw);
if (!leadId && raw.body) hunter(raw.body);
if (!leadId) {
    const bodyStr = JSON.stringify(raw);
    const m = bodyStr.match(/"id"\s*:\s*"?(\d+)"?/i) || bodyStr.match(/\[id\]=(\d+)/i);
    if (m) leadId = m[1];
}
if (!leadId) return [];
return [{ json: { lead_id: leadId } }];

